verify-dotenv-flow.script:
test -f reports/runtime.env || {
  echo '[ERROR] missing reports/runtime.env'
  exit 1
}
test -f out/runtime.env || {
  echo '[ERROR] missing out/runtime.env'
  exit 1
}
test -f out/consume.env || {
  echo '[ERROR] missing out/consume.env'
  exit 1
}
grep -F 'APP_VERSION=1.2.3' reports/runtime.env || {
  echo '[ERROR] APP_VERSION missing from dotenv report'
  exit 1
}
grep -F 'APP_CHANNEL=nightly' out/consume.env || {
  echo '[ERROR] APP_CHANNEL missing from consumed dotenv values'
  exit 1
}
grep -F 'DEPLOY_REGION=ap-southeast-1' out/consume.env || {
  echo '[ERROR] DEPLOY_REGION missing from consumed dotenv values'
  exit 1
}
